  sim::EngineTestAccess_crispin_one_type_manual_attachment_tests::set_deck_seen(engine);

  expect(!sim::EngineTestAccess_crispin_one_type_manual_attachment_tests::crispin_can_advance_energy_axis(engine),
         "a known one-type Crispin line cannot advance Energy after the manual attachment is used");
  expect(!sim::EngineTestAccess_crispin_one_type_manual_attachment_tests::play_crispin(engine),
         "Crispin must be held instead of spending the Supporter play for an unattached Energy");
