  state.bench = {Pokemon{Card::RegidragoVstar, 1, 2, 1, Tool::None}};
  state.hand = {Card::BrilliantBlender};
  state.deck = {Card::TateLiza, Card::MegaDragonite};

  // This is an explicit post-draw tactical state. Forest Seal Stone can search
  // Tate & Liza for switch mode, then the held Brilliant Blender can discard the
  // Dragon payload later in the same turn:
