  state.hand = {Card::BrilliantBlender};
  state.deck = {Card::TateLiza, Card::MegaDragonite};

  // This is an explicit post-draw tactical state. Star Alchemy is one per game.
  // Tate would promote an Energy-incomplete VSTAR, so the VSTAR Power and Blender
  // remain preserved until the selected attacker can pay Apex Dragon's GGF cost:
  // https://api.pokemontcg.io/v2/cards/swsh12-156
  // https://api.pokemontcg.io/v2/cards/sm7-148
