  assert(state.bench.front().card == Card::RegidragoVstar);
  assert(state.bench.front().grass == 1 && state.bench.front().fire == 1);
  assert(contains(state.hand, Card::BrilliantBlender));
  assert(contains(state.deck, Card::TateLiza));
