  // https://api.pokemontcg.io/v2/cards/swsh12tg-TG26
  sim::EngineTestAccess_oricorio_burnet_compression_tests::set_state(engine, std::move(state));

  sim::EngineTestAccess_oricorio_burnet_compression_tests::run_turn(engine);
  const sim::State& after = sim::EngineTestAccess_oricorio_burnet_compression_tests::state(engine);
