  expect(EngineTestAccess_regidrago_policy_tests::payload_ready(strict_current.engine), "Strict JIT should count a payload discarded this turn and still in discard.");
  expect(EngineTestAccess_regidrago_policy_tests::recover_discard_to_hand(strict_current.engine, Card::MegaDragonite), "Fixture should recover the current-turn payload.");
  expect(!EngineTestAccess_regidrago_policy_tests::payload_ready(strict_current.engine), "A payload recovered from discard must not satisfy strict JIT.");

  Fixture no_control(scenario("no-control-old-payload", DciProfile::NoDiscardControl), state(3, Card::RegidragoVstar, 0, 2, 1));
