void test_dipplin_is_legal_treasure_fallback_but_not_payload_ready() {
  State search = state(2, Card::RegidragoV, 1);
  search.bench = {Pokemon{Card::RegidragoV, 1, 0, 0, Tool::None}};
  search.hand = {Card::MysteriousTreasure, Card::RegidragoV};
  search.deck = {Card::Dipplin};
  // Mysterious Treasure searches for a Psychic or Dragon Pokémon: https://api.pokemontcg.io/v2/cards/sm6-113
  // Dipplin TWM 127 is a Dragon Pokémon: https://api.pokemontcg.io/v2/cards/sv6-127
  Fixture legal_search(scenario("mysterious-treasure-dipplin-fallback"), search);
  expect(EngineTestAccess_regidrago_policy_tests::play_mysterious_treasure(legal_search.engine, false),
         "Mysterious Treasure should resolve after its legal Regidrago V discard cost.");
  expect(contains(EngineTestAccess_regidrago_policy_tests::state(legal_search.engine).hand, Card::Dipplin),
         "Mysterious Treasure must take Dipplin when it is the only eligible Dragon fallback.");

  State ready = state(2, Card::RegidragoVstar, 1, 2, 1);
  ready.discard = {Card::Dipplin};
  ready.discarded_this_turn = {Card::Dipplin};
  Fixture excluded_payload(scenario("dipplin-not-as-payload"), ready);
  expect(!EngineTestAccess_regidrago_policy_tests::payload_ready(excluded_payload.engine),
         "Maintainer policy excludes Dipplin from the A/S payload ready-state predicate.");
}

void test_late_jit_item_search_evolves_in_the_same_turn() {
  State s = state(2, Card::RegidragoV, 1, 2, 1);
  s.hand = {Card::MysteriousTreasure, Card::MegaDragonite};
  s.deck = {Card::RegidragoVstar};
  // Mysterious Treasure may discard Mega Dragonite ex, then search the deck for the Dragon Regidrago VSTAR:
  // https://api.pokemontcg.io/v2/cards/sm6-113
  // The active Regidrago V entered play on turn 1, so it can evolve on turn 2 under the core evolution procedure:
  // https://www.pokemon.com/us/pokemon-tcg/rules
  Fixture f(scenario("late-jit-item-search-evolution"), s);
  EngineTestAccess_regidrago_policy_tests::run_turn(f.engine);
  const State& after = EngineTestAccess_regidrago_policy_tests::state(f.engine);
  expect(after.active && after.active->card == Card::RegidragoVstar,
         "A final strict-JIT Item pass that finds VSTAR must be followed by a legal same-turn evolution.");
  expect(contains(after.discard, Card::MegaDragonite) && contains(after.discarded_this_turn, Card::MegaDragonite),
         "The Item route must still produce the current-turn Dragon payload discard.");
  expect(EngineTestAccess_regidrago_policy_tests::payload_ready(f.engine),
         "The resulting VSTAR state must retain the strict current-turn payload requirement.");
}

void test_legacy_star_recovered_crispin_is_played_same_turn() {
  State s = state(2, Card::RegidragoVstar, 0, 1, 0);
  s.discard = {Card::Crispin};
  // Legacy Star discards the top 7 cards, then may recover Crispin from discard:
  // https://api.pokemontcg.io/v2/cards/swsh12-136
  // The two Basic Energy cards remain below that segment for Crispin's different-type search:
  // https://api.pokemontcg.io/v2/cards/sv7-133
  s.deck = {Card::Grass, Card::Fire, Card::MegaDragonite, Card::MawileGX, Card::Guzma,
            Card::Channeler, Card::FieldBlower, Card::ChaoticSwell, Card::PathToPeak};
  Fixture f(scenario("legacy-star-recovered-crispin"), s);
  EngineTestAccess_regidrago_policy_tests::run_turn(f.engine);
  const State& after = EngineTestAccess_regidrago_policy_tests::state(f.engine);
  expect(after.supporter_used && contains(after.discard, Card::Crispin),
         "Recovered Crispin must use the still-available Supporter play.");
  expect(after.active->grass == 2 && after.active->fire == 1,
         "Recovered Crispin plus the manual attachment must complete GGF.");
  expect(EngineTestAccess_regidrago_policy_tests::payload_ready(f.engine),
         "Legacy Star's current-turn Mega Dragonite discard must remain a valid strict-JIT payload.");
}

void test_legacy_star_recovers_burnet_for_deck_payload() {
  State s = state(2, Card::RegidragoVstar, 0, 2, 1);
  s.discard = {Card::ProfessorBurnet};
  // Legacy Star can recover Professor Burnet after its top-seven discard:
  // https://api.pokemontcg.io/v2/cards/swsh12-136
  // Professor Burnet then searches the remaining deck and discards Mega Dragonite ex:
  // https://api.pokemontcg.io/v2/cards/swsh12tg-TG26
  s.deck = {Card::MegaDragonite, Card::MawileGX, Card::Guzma, Card::Channeler,
            Card::FieldBlower, Card::ChaoticSwell, Card::PathToPeak, Card::Powerglass};
  Fixture f(scenario("legacy-star-recovered-burnet"), s);
  EngineTestAccess_regidrago_policy_tests::run_turn(f.engine);
  const State& after = EngineTestAccess_regidrago_policy_tests::state(f.engine);
  expect(after.supporter_used && contains(after.discard, Card::ProfessorBurnet),
         "Recovered Professor Burnet must use the still-available Supporter play.");
  expect(contains(after.discard, Card::MegaDragonite) && contains(after.discarded_this_turn, Card::MegaDragonite),
         "Professor Burnet must discard the remaining Mega Dragonite ex payload.");
  expect(EngineTestAccess_regidrago_policy_tests::payload_ready(f.engine),
         "Professor Burnet's discard must satisfy the strict-JIT payload readiness predicate.");
}

