  EngineTestAccess_regidrago_tier2_tests::choose_supporter(f.engine);
  State& a = EngineTestAccess_regidrago_tier2_tests::state(f.engine);
  expect(has(a.hand, Card::Lusamine), "Known prize Lusamine should be taken only when no direct Supporter route exists.");
