  sim::EngineTestAccess_route_reconciliation_tests::set_state(engine, std::move(state));

  expect(!sim::EngineTestAccess_route_reconciliation_tests::play_ultra_ball(engine, true),
         "The first Ultra Ball must be held when a second Ultra Ball would lack a distinct second cost.");
