    sim::EngineTestAccess_wonder_tag_known_dead_burnet_tests::set_state(engine, std::move(state));
    sim::EngineTestAccess_wonder_tag_known_dead_burnet_tests::set_deck_seen(engine, true);
    // Steven's Resolve remains a searchable turn-one compression target:
